from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregated_results = defaultdict(dict)

    # Helper function to safely extract field value from metadata
    def get_field_value(metadata: dict, field: str) -> Any:
        """Extract field value from metadata, return None if missing"""
        return metadata.get(field) if metadata else None

    # Iterate through each SearchResult
    for result in search_results:
        # Extract metadata and group value
        metadata = result.metadata or {}
        group_value = get_field_value(metadata, group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_key = "unknown"
        else:
            group_key = str(group_value)

        # Initialize group statistics if not exists
        if group_key not in aggregated_results:
            aggregated_results[group_key] = {
                "count": 0,
                "sum_scores": 0.0,
                "max_score": float("-inf"),
                "min_score": float("inf"),
                "custom_aggregations": {}
            }

        # Update default statistics
        aggregated_results[group_key]["count"] += 1
        aggregated_results[group_key]["sum_scores"] += result.score
        if result.score > aggregated_results[group_key]["max_score"]:
            aggregated_results[group_key]["max_score"] = result.score
        if result.score < aggregated_results[group_key]["min_score"]:
            aggregated_results[group_key]["min_score"] = result.score

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                # Extract field value from metadata
                field_value = get_field_value(metadata, field_name)

                # Initialize custom aggregation storage
                if field_name not in aggregated_results[group_key]["custom_aggregations"]:
                    aggregated_results[group_key]["custom_aggregations"][field_name] = []

                # Apply aggregation function and store result
                try:
                    result_val = func(field_value)
                    aggregated_results[group_key]["custom_aggregations"][field_name].append(result_val)
                except Exception as e:
                    # Handle function application errors gracefully
                    aggregated_results[group_key]["custom_aggregations"][field_name].append(None)

    # Calculate final statistics (average, etc.)
    for group_key in aggregated_results:
        stats = aggregated_results[group_key]
        count = stats["count"]

        # Calculate average score
        if count > 0:
            stats["avg_score"] = stats["sum_scores"] / count
        else:
            stats["avg_score"] = 0.0

        # Process custom aggregations (calculate final values)
        if "custom_aggregations" in stats and stats["custom_aggregations"]:
            for field_name, values in stats["custom_aggregations"].items():
                if values:
                    try:
                        # Calculate final aggregation value
                        final_value = func(values)  # Use appropriate aggregation function
                        stats[field_name] = final_value
                    except Exception as e:
                        stats[field_name] = None
                else:
                    stats[field_name] = None

    # Convert defaultdict to regular dict for cleaner output
    return dict(aggregated_results)

